spec:
// Import from '@/schemas'

// User
export const UserSchema: z.ZodObject<{id, email, name, timezone, week_start_day, created_at?, updated_at?}>;
export const UpdateUserSchema: z.ZodObject<{name?, timezone?, week_start_day?}>;
export type User = z.infer<typeof UserSchema>;
export type UpdateUserInput = z.infer<typeof UpdateUserSchema>;

// Category
export const CategorySchema: z.ZodObject<{id, user_id, name, color, type, created_at}>;
export const CreateCategorySchema: z.ZodObject<{name, color, type}>; // NO id, user_id, created_at
export const UpdateCategorySchema: z.ZodObject<{name?, color?, type?}>;
export const CategoryIdSchema: z.ZodNullable<z.ZodOptional<z.ZodString>>; // For validating category_id refs
export type Category, CreateCategoryInput, UpdateCategoryInput;

// TimeEntry
export const TimeEntrySchema: z.ZodObject<{id, user_id, category_id, start_at, end_at, duration_seconds, notes, created_at, updated_at}>;
export const CreateTimeEntrySchema: z.ZodObject<{category_id?, start_at, end_at?, duration_seconds, notes?}>; // NO id, user_id, timestamps
export const UpdateTimeEntrySchema: z.ZodObject<{category_id?, start_at?, end_at?, duration_seconds?, notes?}>;
export const TimeEntryFiltersSchema: z.ZodObject<{dateStart?, dateEnd?, categoryId?, searchNotes?, minDuration?, maxDuration?}>;
export type TimeEntry, CreateTimeEntryInput, UpdateTimeEntryInput, TimeEntryFilters;

// Timer
export const ActiveTimerSchema: z.ZodObject<{id, user_id, category_id, started_at, running}>;
export const StartTimerSchema: z.ZodObject<{category_id?}>; // NO started_at - server sets it
export const StopTimerSchema: z.ZodObject<{notes?}>;
export const QueuedActionSchema: z.ZodObject<{id, action, payload, timestamp, retryCount}>;
export type ActiveTimer, StartTimerInput, StopTimerInput, TimerState, QueuedAction;

// Goal
export const MonthlyGoalSchema: z.ZodObject<{id, user_id, month, category_id, target_hours}>;
export const CreateGoalSchema: z.ZodObject<{month, category_id?, target_hours}>; // NO id, user_id
export const UpdateGoalSchema: z.ZodObject<{target_hours?}>;
export const SetOverallGoalSchema: z.ZodObject<{month, target_hours}>; // For overall goals (category_id IS NULL)
export const SetCategoryGoalSchema: z.ZodObject<{month, category_id, target_hours}>; // For per-category goals
export type MonthlyGoal, CreateGoalInput, UpdateGoalInput, SetOverallGoalInput, SetCategoryGoalInput, GoalProgress;
